const r = $input.first().json;
const raw = String(r.stdout ?? '').trim();
const nl = raw.lastIndexOf('\n');
const status = Number(nl === -1 ? raw : raw.slice(nl + 1));
const text = nl === -1 ? '' : raw.slice(0, nl).trim();
let body = null;
try { body = JSON.parse(text); } catch (e) {}
if (!Number.isFinite(status) || status >= 400 || !body || body.ok !== true) {
  const cause = (body && (body.error || body.message)) || text.slice(0, 300) || String(r.stderr || '').slice(0, 200) || 'no response';
  throw new Error('page-api add-page failed (HTTP ' + status + '): ' + cause);
}
return [{ json: body }];

